#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define LOG_DIVISIONS	10
#define DIVISIONS		(1 << LOG_DIVISIONS)
#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1

#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128

#define BIN_COUNT 1024
#define WARP_LOG_SIZE 5
#define WARP_N 3

#ifdef HISTO_WG_SIZE_0
#define THREAD_N HISTO_WG_SIZE_0
#else
#define THREAD_N (WARP_N << WARP_LOG_SIZE)
#endif

#define BLOCK_MEMORY (WARP_N * BIN_COUNT)

static inline unsigned int addOffset(volatile unsigned int *s_offset, unsigned int data, unsigned int threadTag) {
    unsigned int count;
    do {
        count = s_offset[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_offset[data] = count;
    } while (s_offset[data] != count);
    return (count & 0x07FFFFFFU) - 1;
}

static inline void addData1024(volatile unsigned int *s_WarpHist, unsigned int data, unsigned int threadTag) {
    unsigned int count;
    do {
        count = s_WarpHist[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_WarpHist[data] = count;
    } while (s_WarpHist[data] != count);
}

__kernel void histogram1024Kernel(__global unsigned int *d_Result, __global float *d_Data, float minimum, float maximum, int dataN) {
    const int globalTid = blockIdx.x * blockDim.x + threadIdx.x;
    const int numThreads = blockDim.x * gridDim.x;
    const unsigned int threadTag = threadIdx.x << (32 - WARP_LOG_SIZE);
    volatile __shared__ unsigned int s_Hist[BLOCK_MEMORY];
    const int warpBase = (threadIdx.x >> WARP_LOG_SIZE) * BIN_COUNT;

    for (int pos = threadIdx.x; pos < BLOCK_MEMORY; pos += blockDim.x)
        s_Hist[pos] = 0;

    __syncthreads();

    for (int pos = globalTid; pos < dataN; pos += numThreads) {
        unsigned int data4 = ((d_Data[pos] - minimum) / (maximum - minimum)) * BIN_COUNT;
        addData1024(s_Hist + warpBase, data4 & 0x3FFU, threadTag);
    }

    __syncthreads();

    for (int pos = threadIdx.x; pos < BIN_COUNT; pos += blockDim.x) {
        unsigned int sum = 0;
        for (int base = 0; base < BLOCK_MEMORY; base += BIN_COUNT)
            sum += s_Hist[base + pos] & 0x07FFFFFFU;
        atomic_add(&d_Result[pos], sum);
    }
}

__kernel void bucketcount(__global float *input, __global int *indice, __global unsigned int *d_prefixoffsets, int size, __global float *l_pivotpoints) {
    volatile __shared__ unsigned int s_offset[BUCKET_BLOCK_MEMORY];
    const unsigned int threadTag = threadIdx.x << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (threadIdx.x >> BUCKET_WARP_LOG_SIZE) * DIVISIONS;
    const int numThreads = blockDim.x * gridDim.x;

    for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
        s_offset[i] = 0;

    __syncthreads();

    for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads) {
        float elem = input[tid];
        int idx = DIVISIONS / 2 - 1;
        int jump = DIVISIONS / 4;
        float piv = l_pivotpoints[idx];

        while (jump >= 1) {
            idx = (elem < piv) ? (idx - jump) : (idx + jump);
            piv = l_pivotpoints[idx];
            jump /= 2;
        }
        idx = (elem < piv) ? idx : (idx + 1);

        indice[tid] = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;
    }

    __syncthreads();

    int prefixBase = blockIdx.x * BUCKET_BLOCK_MEMORY;
    for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
        d_prefixoffsets[prefixBase + i] = s_offset[i] & 0x07FFFFFFU;
}

__kernel void bucketprefixoffset(__global unsigned int *d_prefixoffsets, __global unsigned int *d_offsets, int blocks) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int size = blocks * BUCKET_BLOCK_MEMORY;
    int sum = 0;

    for (int i = tid; i < size; i += DIVISIONS) {
        int x = d_prefixoffsets[i];
        d_prefixoffsets[i] = sum;
        sum += x;
    }

    d_offsets[tid] = sum;
}

__kernel void bucketsort(__global float *input, __global int *indice, __global float *output, int size, __global unsigned int *d_prefixoffsets, __global unsigned int *l_offsets) {
    volatile __shared__ unsigned int s_offset[BUCKET_BLOCK_MEMORY];
    int prefixBase = blockIdx.x * BUCKET_BLOCK_MEMORY;
    const int warpBase = (threadIdx.x >> BUCKET_WARP_LOG_SIZE) * DIVISIONS;
    const int numThreads = blockDim.x * gridDim.x;

    for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
        s_offset[i] = l_offsets[i & (DIVISIONS - 1)] + d_prefixoffsets[prefixBase + i];

    __syncthreads();

    for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads) {
        float elem = input[tid];
        int id = indice[tid];
        output[s_offset[warpBase + (id & (DIVISIONS - 1))] + (id >> LOG_DIVISIONS)] = elem;
    }
}

